import React, { useEffect, useRef, useState } from 'react';
import {
  Stage,
  Layer,
  Group,
  Image as KonvaImage,
  Rect,
  Line,
  Circle,
  Ellipse,
  Transformer,
} from 'react-konva';
import './AnnotationCanvas.css';

export default function AnnotationCanvas({
  fileUrl,
  annotations,
  onAnnotationsChange,
  selectedTool,
  scale,
  onWheelZoom,
  activeLabelColor,
  onFinishShape,
}) {
  const stageRef = useRef(null);
  const containerRef = useRef(null);

  const [dims, setDims] = useState({ width: 0, height: 0 });
  const [konvaImg, setKonvaImg] = useState(null);

  // Master group offset (image panning)
  const [imagePos, setImagePos] = useState({ x: 0, y: 0 });

  // In-progress shapes
  const [newBox, setNewBox] = useState(null);
  const [tempPoints, setTempPoints] = useState([]);
  const [drawingPolygon, setDrawingPolygon] = useState(false);
  const [tempPolyline, setTempPolyline] = useState([]);
  const [drawingPolyline, setDrawingPolyline] = useState(false);
  const [newEllipse, setNewEllipse] = useState(null);

  // For selecting shape to resize with Transformer
  const [selectedAnnotationIndex, setSelectedAnnotationIndex] = useState(null);
  const transformerRef = useRef(null);

  // We only attach bounding boxes / ellipses to shapeRefs for Transformer,
  // because polygons/polylines/points will not use bounding‐box scaling.
  const shapeRefs = useRef([]);

  // ----------- Window / container sizing -----------
  useEffect(() => {
    const handleResize = () => {
      if (!containerRef.current) return;
      setDims({
        width: containerRef.current.offsetWidth,
        height: containerRef.current.offsetHeight,
      });
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // ----------- Load image -----------
  useEffect(() => {
    if (!fileUrl) return;
    const img = new window.Image();
    img.src = fileUrl;
    img.onload = () => {
      setKonvaImg(img);
      setImagePos({ x: 0, y: 0 });
    };
    img.onerror = () => console.error('Could not load image:', fileUrl);
  }, [fileUrl]);

  // ----------- Flatten {x,y} => [x,y,x,y,...] -----------
  function flattenPoints(pts) {
    return pts.flatMap((p) => [p.x, p.y]);
  }

  // ----------- Relative pointer in #anno-group -----------
  function getGroupPos(evt) {
    const group = stageRef.current?.findOne('#anno-group');
    return group ? group.getRelativePointerPosition() : null;
  }

  // ----------- Check if shape is outside the image -----------
  function shapeBoundingBox(ann) {
    if (ann.type === 'bbox') {
      return {
        x1: ann.x,
        y1: ann.y,
        x2: ann.x + ann.width,
        y2: ann.y + ann.height,
      };
    } else if (ann.type === 'ellipse') {
      return {
        x1: ann.x - ann.radiusX,
        y1: ann.y - ann.radiusY,
        x2: ann.x + ann.radiusX,
        y2: ann.y + ann.radiusY,
      };
    } else if (ann.type === 'polygon' || ann.type === 'polyline') {
      let minX = Infinity,
        minY = Infinity,
        maxX = -Infinity,
        maxY = -Infinity;
      ann.points.forEach((pt) => {
        if (pt.x < minX) minX = pt.x;
        if (pt.y < minY) minY = pt.y;
        if (pt.x > maxX) maxX = pt.x;
        if (pt.y > maxY) maxY = pt.y;
      });
      return { x1: minX, y1: minY, x2: maxX, y2: maxY };
    } else if (ann.type === 'point') {
      return {
        x1: ann.x,
        y1: ann.y,
        x2: ann.x,
        y2: ann.y,
      };
    }
    return null;
  }
  function isOutsideImage(ann) {
    if (!konvaImg) return false;
    const { x1, y1, x2, y2 } = shapeBoundingBox(ann);
    // If shape's bounding box is totally out of the image
    if (x2 < 0 || x1 > konvaImg.width || y2 < 0 || y1 > konvaImg.height) {
      return true;
    }
    return false;
  }

  // ----------- Cancel shape creation on ESC -----------
  useEffect(() => {
    const onCancelAnnotation = () => {
      setNewBox(null);
      setTempPoints([]);
      setDrawingPolygon(false);
      setTempPolyline([]);
      setDrawingPolyline(false);
      setNewEllipse(null);
    };
    window.addEventListener('cancel-annotation', onCancelAnnotation);
    return () => window.removeEventListener('cancel-annotation', onCancelAnnotation);
  }, []);

  // ----------- Wheel Zoom -----------
  function handleWheel(evt) {
    evt.evt.preventDefault();
    onWheelZoom(evt.evt.deltaY);
  }

  // ------------------------------------------------------------------
  // ------------------ SHAPE CREATION LOGIC ---------------------------
  // ------------------------------------------------------------------

  // 1) BBox
  function startBox(pos) {
    setNewBox({ x: pos.x, y: pos.y, width: 0, height: 0 });
  }
  function updateBox(pos) {
    if (!newBox) return;
    setNewBox({
      ...newBox,
      width: pos.x - newBox.x,
      height: pos.y - newBox.y,
    });
  }
  function finalizeBox() {
    if (!newBox) return;
    const newAnn = { type: 'bbox', ...newBox, label: '' };
    if (!isOutsideImage(newAnn)) {
      onAnnotationsChange([...annotations, newAnn]);
    }
    setNewBox(null);
    onFinishShape && onFinishShape();
  }

  // 2) Polygon
  function addPolygonPoint(pos) {
    setTempPoints((prev) => [...prev, pos]);
    setDrawingPolygon(true);
  }
  function finalizePolygon() {
    if (tempPoints.length >= 3) {
      const newAnn = { type: 'polygon', points: tempPoints, label: '' };
      if (!isOutsideImage(newAnn)) {
        onAnnotationsChange([...annotations, newAnn]);
      }
    }
    setTempPoints([]);
    setDrawingPolygon(false);
    onFinishShape && onFinishShape();
  }

  // 3) Polyline
  function addPolylinePoint(pos) {
    setTempPolyline((prev) => [...prev, pos]);
    setDrawingPolyline(true);
  }
  function finalizePolyline() {
    if (tempPolyline.length >= 2) {
      const newAnn = { type: 'polyline', points: tempPolyline, label: '' };
      if (!isOutsideImage(newAnn)) {
        onAnnotationsChange([...annotations, newAnn]);
      }
    }
    setTempPolyline([]);
    setDrawingPolyline(false);
    onFinishShape && onFinishShape();
  }

  // 4) Point
  function addPoint(pos) {
    const newAnn = { type: 'point', x: pos.x, y: pos.y, label: '' };
    if (!isOutsideImage(newAnn)) {
      onAnnotationsChange([...annotations, newAnn]);
    }
    onFinishShape && onFinishShape();
  }

  // 5) Ellipse
  function startEllipse(pos) {
    setNewEllipse({
      type: 'ellipse',
      x: pos.x,
      y: pos.y,
      radiusX: 0,
      radiusY: 0,
      rotation: 0,
      label: '',
    });
  }
  function updateEllipse(pos) {
    if (!newEllipse) return;
    const rx = Math.abs(pos.x - newEllipse.x);
    const ry = Math.abs(pos.y - newEllipse.y);
    setNewEllipse({
      ...newEllipse,
      radiusX: rx,
      radiusY: ry,
    });
  }
  function finalizeEllipse() {
    if (!newEllipse) return;
    if (!isOutsideImage(newEllipse)) {
      onAnnotationsChange([...annotations, { ...newEllipse }]);
    }
    setNewEllipse(null);
    onFinishShape && onFinishShape();
  }

  // ------------------------------------------------------------------
  // ------------------ Mouse-based shape creation ---------------------
  // ------------------------------------------------------------------
  function handleMouseDown(evt) {
    if (selectedTool === 'move') {
      return; // let user pan if they drag empty space
    }
    const pos = getGroupPos(evt);
    if (!pos) return;

    switch (selectedTool) {
      case 'bbox':
        startBox(pos);
        break;
      case 'polygon':
        addPolygonPoint(pos);
        break;
      case 'polyline':
        addPolylinePoint(pos);
        break;
      case 'point':
        addPoint(pos);
        break;
      case 'ellipse':
        startEllipse(pos);
        break;
      default:
        break;
    }
  }
  function handleMouseMove(evt) {
    if (selectedTool === 'bbox' && newBox) {
      const pos = getGroupPos(evt);
      if (pos) updateBox(pos);
    } else if (selectedTool === 'ellipse' && newEllipse) {
      const pos = getGroupPos(evt);
      if (pos) updateEllipse(pos);
    }
  }
  function handleMouseUp() {
    if (selectedTool === 'bbox' && newBox) {
      finalizeBox();
    } else if (selectedTool === 'ellipse' && newEllipse) {
      finalizeEllipse();
    }
  }
  function handleDblClick() {
    if (selectedTool === 'polygon' && drawingPolygon) {
      finalizePolygon();
    } else if (selectedTool === 'polyline' && drawingPolyline) {
      finalizePolyline();
    }
  }

  // ------------------------------------------------------------------
  // ------------------ Existing shape dragging logic ------------------
  // ------------------------------------------------------------------

  // BBox
  function handleBBoxDragEnd(index, e) {
    const { x, y } = e.target.position();
    const updated = [...annotations];
    updated[index] = { ...updated[index], x, y };
    if (isOutsideImage(updated[index])) {
      updated.splice(index, 1);
    }
    onAnnotationsChange(updated);
  }

  // Ellipse
  function handleEllipseDragEnd(index, e) {
    const { x, y } = e.target.position();
    const updated = [...annotations];
    updated[index] = { ...updated[index], x, y };
    if (isOutsideImage(updated[index])) {
      updated.splice(index, 1);
    }
    onAnnotationsChange(updated);
  }

  // Point (no resizing, just drag)
  function handlePointDragEnd(index, e) {
    const { x, y } = e.target.position();
    const updated = [...annotations];
    updated[index] = { ...updated[index], x, y };
    if (isOutsideImage(updated[index])) {
      updated.splice(index, 1);
    }
    onAnnotationsChange(updated);
  }

  // For polygon & polyline: group-based dragging
  // plus we will add vertex anchor circles if shape is selected
  function handlePolygonGroupDragEnd(ann, index, groupNode) {
    const { x, y } = groupNode.position();
    // shift all points by (x,y)
    const newPoints = ann.points.map((pt) => ({
      x: pt.x + x,
      y: pt.y + y,
    }));
    const updated = [...annotations];
    updated[index] = { ...ann, points: newPoints };
    // reset group position to (0,0)
    groupNode.position({ x: 0, y: 0 });
    if (isOutsideImage(updated[index])) {
      updated.splice(index, 1);
    }
    onAnnotationsChange(updated);
  }

  // Vertex anchor for polygons/polylines
  // Drags a single point
  function handleVertexDrag(ann, index, vertexIdx, x, y) {
    const updatedArr = [...annotations];
    const newPoints = [...ann.points];
    newPoints[vertexIdx] = { x, y };
    updatedArr[index] = { ...ann, points: newPoints };
    onAnnotationsChange(updatedArr);
  }

  // ------------------------------------------------------------------
  // ------------------ Transformer (for bbox & ellipse only) ----------
  // ------------------------------------------------------------------
  useEffect(() => {
    const tr = transformerRef.current;
    if (!tr) return;

    // If no shape is selected, clear
    if (selectedAnnotationIndex == null) {
      tr.nodes([]);
      return;
    }

    const ann = annotations[selectedAnnotationIndex];
    // Only attach the transformer if it's a bbox or ellipse
    if (ann.type === 'bbox' || ann.type === 'ellipse') {
      const node = shapeRefs.current[selectedAnnotationIndex];
      if (node) {
        tr.nodes([node]);
        tr.getLayer().batchDraw();
      } else {
        tr.nodes([]);
      }
    } else {
      // Polygons, polylines, points => do not use Transformer
      tr.nodes([]);
    }
  }, [selectedAnnotationIndex, annotations, onAnnotationsChange]);

  // On transform end => only handle BBox / Ellipse
  function handleTransformEnd() {
    if (selectedAnnotationIndex == null) return;
    const ann = annotations[selectedAnnotationIndex];
    if (!ann) return;

    // We only do bounding box scaling for bboxes/ellipses
    if (ann.type !== 'bbox' && ann.type !== 'ellipse') {
      return;
    }

    const shapeNode = shapeRefs.current[selectedAnnotationIndex];
    if (!shapeNode) return;

    const scaleX = shapeNode.scaleX();
    const scaleY = shapeNode.scaleY();
    const offsetX = shapeNode.x();
    const offsetY = shapeNode.y();

    let updatedAnn = { ...ann };

    if (ann.type === 'bbox') {
      // For Rect, node.width() is original width
      const newWidth = shapeNode.width() * scaleX;
      const newHeight = shapeNode.height() * scaleY;
      updatedAnn.x = offsetX;
      updatedAnn.y = offsetY;
      updatedAnn.width = newWidth;
      updatedAnn.height = newHeight;
    } else if (ann.type === 'ellipse') {
      // Konva Ellipse => node.width() = 2 * radiusX
      const newRadiusX = (shapeNode.width() / 2) * scaleX;
      const newRadiusY = (shapeNode.height() / 2) * scaleY;
      updatedAnn.x = offsetX;
      updatedAnn.y = offsetY;
      updatedAnn.radiusX = newRadiusX;
      updatedAnn.radiusY = newRadiusY;
      // If you allow rotation => updatedAnn.rotation = shapeNode.rotation()
    }

    // Reset the node transform
    shapeNode.scaleX(1);
    shapeNode.scaleY(1);
    shapeNode.x(0);
    shapeNode.y(0);

    // Save updated shape
    const updatedAll = [...annotations];
    updatedAll[selectedAnnotationIndex] = updatedAnn;

    // If out of image => remove
    if (isOutsideImage(updatedAnn)) {
      updatedAll.splice(selectedAnnotationIndex, 1);
    }
    onAnnotationsChange(updatedAll);
  }

  // ------------------------------------------------------------------
  // ------------------ Render Polygons & Polylines --------------------
  // ------------------------------------------------------------------
  function PolygonShape({ ann, index }) {
    const groupRef = useRef(null);
    // The shape is fully draggable
    // We also add anchor circles if selected

    return (
      <Group
        draggable
        ref={groupRef}
        onDragEnd={(e) => handlePolygonGroupDragEnd(ann, index, groupRef.current)}
        onClick={(e) => {
          // If in move mode, we can select it
          if (selectedTool === 'move') {
            setSelectedAnnotationIndex(index);
          }
        }}
      >
        {/* The main polygon line: set listening=false so group can get drag events */}
        <Line
          points={flattenPoints(ann.points)}
          fill={activeLabelColor + '55'}
          stroke={activeLabelColor}
          strokeWidth={2 / scale}
          closed
          listening={false}
        />
        {/* If this polygon is selected, show vertex anchors */}
        {selectedAnnotationIndex === index &&
          ann.points.map((pt, vi) => (
            <Circle
              key={vi}
              x={pt.x}
              y={pt.y}
              radius={5 / scale}
              fill="#fff"
              stroke="#000"
              strokeWidth={1 / scale}
              draggable
              onDragMove={(evt) => {
                const { x, y } = evt.target.position();
                handleVertexDrag(ann, index, vi, x, y);
              }}
              onDragEnd={(evt) => {
                // If entire shape is out of image, remove it
                const updatedShape = annotations[index];
                if (isOutsideImage(updatedShape)) {
                  const updatedAll = [...annotations];
                  updatedAll.splice(index, 1);
                  onAnnotationsChange(updatedAll);
                }
              }}
            />
          ))}
      </Group>
    );
  }

  function PolylineShape({ ann, index }) {
    const groupRef = useRef(null);

    return (
      <Group
        draggable
        ref={groupRef}
        onDragEnd={(e) => handlePolygonGroupDragEnd(ann, index, groupRef.current)}
        onClick={(e) => {
          if (selectedTool === 'move') {
            setSelectedAnnotationIndex(index);
          }
        }}
      >
        <Line
          points={flattenPoints(ann.points)}
          stroke={activeLabelColor}
          strokeWidth={2 / scale}
          closed={false}
          listening={false}
        />
        {/* Vertex anchors if selected */}
        {selectedAnnotationIndex === index &&
          ann.points.map((pt, vi) => (
            <Circle
              key={vi}
              x={pt.x}
              y={pt.y}
              radius={5 / scale}
              fill="#fff"
              stroke="#000"
              strokeWidth={1 / scale}
              draggable
              onDragMove={(evt) => {
                const { x, y } = evt.target.position();
                handleVertexDrag(ann, index, vi, x, y);
              }}
              onDragEnd={(evt) => {
                const updatedShape = annotations[index];
                if (isOutsideImage(updatedShape)) {
                  const updatedAll = [...annotations];
                  updatedAll.splice(index, 1);
                  onAnnotationsChange(updatedAll);
                }
              }}
            />
          ))}
      </Group>
    );
  }

  // ------------------------------------------------------------------
  // ------------------ Final Render ----------------------------------
  // ------------------------------------------------------------------
  const fillColor = activeLabelColor + '55';

  return (
    <div className="canvas-container" ref={containerRef}>
      <Stage
        ref={stageRef}
        width={dims.width}
        height={dims.height}
        scaleX={scale}
        scaleY={scale}
        style={{ background: '#dfe6e9' }}
        onWheel={handleWheel}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onDblClick={handleDblClick}
      >
        <Layer>
          <Group
            id="anno-group"
            draggable={selectedTool === 'move'}
            x={imagePos.x}
            y={imagePos.y}
            onDragEnd={(e) => {
              setImagePos({ x: e.target.x(), y: e.target.y() });
            }}
          >
            {konvaImg && (
              <KonvaImage
                image={konvaImg}
                width={konvaImg.width}
                height={konvaImg.height}
              />
            )}

            {/* Render existing shapes */}
            {annotations.map((ann, i) => {
              if (ann.type === 'bbox') {
                // BBox => attach to shapeRefs for Transformer
                return (
                  <Rect
                    key={i}
                    ref={(node) => (shapeRefs.current[i] = node)}
                    x={ann.x}
                    y={ann.y}
                    width={ann.width}
                    height={ann.height}
                    fill={fillColor}
                    stroke={activeLabelColor}
                    strokeWidth={2 / scale}
                    draggable
                    onDragEnd={(e) => handleBBoxDragEnd(i, e)}
                    onClick={(e) => {
                      if (selectedTool === 'move') {
                        setSelectedAnnotationIndex(i);
                      }
                    }}
                  />
                );
              } else if (ann.type === 'ellipse') {
                // Ellipse => attach to shapeRefs for Transformer
                return (
                  <Ellipse
                    key={i}
                    ref={(node) => (shapeRefs.current[i] = node)}
                    x={ann.x}
                    y={ann.y}
                    radiusX={ann.radiusX}
                    radiusY={ann.radiusY}
                    rotation={ann.rotation || 0}
                    fill={fillColor}
                    stroke={activeLabelColor}
                    strokeWidth={2 / scale}
                    draggable
                    onDragEnd={(e) => handleEllipseDragEnd(i, e)}
                    onClick={(e) => {
                      if (selectedTool === 'move') {
                        setSelectedAnnotationIndex(i);
                      }
                    }}
                  />
                );
              } else if (ann.type === 'point') {
                // Points => NO transformer usage
                return (
                  <Circle
                    key={i}
                    // We do NOT store in shapeRefs because we don't want bounding box resizing
                    x={ann.x}
                    y={ann.y}
                    radius={6 / scale}
                    fill={activeLabelColor}
                    draggable
                    onDragEnd={(e) => handlePointDragEnd(i, e)}
                    onClick={(e) => {
                      if (selectedTool === 'move') {
                        setSelectedAnnotationIndex(i);
                      }
                    }}
                  />
                );
              } else if (ann.type === 'polygon') {
                return (
                  <PolygonShape
                    key={i}
                    ann={ann}
                    index={i}
                    annotations={annotations}
                    onAnnotationsChange={onAnnotationsChange}
                    selectedTool={selectedTool}
                    selectedAnnotationIndex={selectedAnnotationIndex}
                    setSelectedAnnotationIndex={setSelectedAnnotationIndex}
                    scale={scale}
                    activeLabelColor={activeLabelColor}
                    isOutsideImage={isOutsideImage}
                  />
                );
              } else if (ann.type === 'polyline') {
                return (
                  <PolylineShape
                    key={i}
                    ann={ann}
                    index={i}
                    annotations={annotations}
                    onAnnotationsChange={onAnnotationsChange}
                    selectedTool={selectedTool}
                    selectedAnnotationIndex={selectedAnnotationIndex}
                    setSelectedAnnotationIndex={setSelectedAnnotationIndex}
                    scale={scale}
                    activeLabelColor={activeLabelColor}
                    isOutsideImage={isOutsideImage}
                  />
                );
              }
              return null;
            })}

            {/* In-progress BBox */}
            {newBox && selectedTool === 'bbox' && (
              <Rect
                x={newBox.x}
                y={newBox.y}
                width={newBox.width}
                height={newBox.height}
                fill={fillColor}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
              />
            )}

            {/* In-progress Polygon */}
            {drawingPolygon && tempPoints.length > 1 && selectedTool === 'polygon' && (
              <Line
                points={flattenPoints([...tempPoints, tempPoints[0]])}
                fill={fillColor}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
                closed
              />
            )}

            {/* In-progress Polyline */}
            {drawingPolyline && tempPolyline.length > 1 && selectedTool === 'polyline' && (
              <Line
                points={flattenPoints(tempPolyline)}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
                closed={false}
              />
            )}

            {/* In-progress Ellipse */}
            {newEllipse && selectedTool === 'ellipse' && (
              <Ellipse
                x={newEllipse.x}
                y={newEllipse.y}
                radiusX={newEllipse.radiusX}
                radiusY={newEllipse.radiusY}
                rotation={0}
                fill={fillColor}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
              />
            )}
          </Group>

          {/* A single Transformer to resize BBox/Ellipse only */}
          <Transformer
            ref={transformerRef}
            rotateEnabled={false}
            anchorSize={8}
            borderDash={[6, 2]}
            onTransformEnd={handleTransformEnd}
            onDragEnd={handleTransformEnd}
          />
        </Layer>
      </Stage>
    </div>
  );
}
